#define HALL_PIN 2
int rpmCount = 0;
void setup() {
  Serial.begin(9600);
  pinMode(HALL_PIN, INPUT_PULLUP);
  // Count each magnet pass for RPM:
  attachInterrupt(digitalPinToInterrupt(HALL_PIN),
    []() { rpmCount++; }, FALLING);
}
void loop() {
  // Print RPM every second
  Serial.print("Pulses/sec (RPM approx): ");
  Serial.println(rpmCount * 60);
  rpmCount = 0;
  delay(1000);
}
